const hashtag = $('Form Trigger — Configuración').first().json['Hashtag de la publicación'] || '#21AnuarioCorresponsables';
const publicacion = $('Form Trigger — Configuración').first().json['Nombre de la publicación'] || 'Anuario Corresponsables 2026 (21ª edición)';
const urlBaseRaw = $('Form Trigger — Configuración').first().json['URL base de la publicación'] || 'https://publicaciones.corresponsables.com/publication/6f073ea8/';
const urlBase = urlBaseRaw.replace(/\/?$/, '/') + '?p=';

const items = [];

for (const item of $input.all()) {
  const fileId = item.json._fileId || '';
  const imagenUrl = fileId
    ? 'https://drive.google.com/uc?export=view&id=' + fileId
    : '';
  const raw = item.json.choices?.[0]?.message?.content || '';

  // Intentar parsear como array o como objeto único
  let contenidos = [];
  try {
    const clean = raw.replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(clean);
    // Normalizar siempre a array
    contenidos = Array.isArray(parsed) ? parsed : [parsed];
  } catch (e) {
    items.push({ json: {
      pagina: 'ERROR', empresa: item.json._fileId || '',
      portavoz: '', categoria: 'ERROR_PARSE',
      tipo_contenido: e.message, seccion_tematica: '',
      ods: '', datos_clave: raw.substring(0, 300),
      red_social: 'N/A', copy: 'ERROR: No se pudo parsear la respuesta de GPT-4o',
      hashtags: '', url: '', imagen_url: imagenUrl,
      fecha_generacion: new Date().toISOString().split('T')[0]
    }});
    continue;
  }

  for (const parsed of contenidos) {
    if (!parsed.empresa) continue;

    const url = parsed.url || (urlBase + parsed.pagina);
    const odsStr = Array.isArray(parsed.ods) ? parsed.ods.map(o => 'ODS ' + o).join(', ') : (parsed.ods || '');
    const datosStr = Array.isArray(parsed.datos_clave) ? parsed.datos_clave.join(' | ') : (parsed.datos_clave || '');
    const hashtagsSector = Array.isArray(parsed.hashtags_sector) ? parsed.hashtags_sector.join(' ') : '';

    const posts = [
      { version: 'LinkedIn v1', copy: parsed.linkedin_1 },
      { version: 'LinkedIn v2', copy: parsed.linkedin_2 },
      { version: 'LinkedIn v3', copy: parsed.linkedin_3 }
    ];

    for (const p of posts) {
      if (!p.copy) continue;
      items.push({ json: {
        pagina: parsed.pagina,
        empresa: parsed.empresa,
        portavoz: parsed.portavoz || '',
        categoria: parsed.categoria,
        tipo_contenido: parsed.tipo_contenido,
        seccion_tematica: parsed.seccion_tematica,
        ods: odsStr,
        datos_clave: datosStr,
        red_social: p.version,
        copy: p.copy,
        hashtags: hashtagsSector,
        url: url,
        imagen_url: imagenUrl,
        fecha_generacion: new Date().toISOString().split('T')[0]
      }});
    }
  }
}

if (items.length === 0) throw new Error('No se procesó ningún ítem correctamente.');
return items;

const rows = $input.first().json.rows || [];

const formatted = rows
  .filter(r => r.pagina !== 'ERROR')
  .map(r => ({
    json: {
      'Página': r.pagina,
      'Empresa': r.empresa,
      'Portavoz': r.portavoz,
      'Categoría': r.categoria,
      'Tipo de contenido': r.tipo_contenido,
      'Sección temática': r.seccion_tematica,
      'ODS': r.ods,
      'Datos clave': r.datos_clave,
      'Red social': r.red_social,
      'Copy': r.copy,
      'URL Imagen': r.imagen_url || '',
      'Hashtags': r.hashtags,
      'URL': r.url,
      'Fecha generación': r.fecha_generacion
    }
  }));

if (formatted.length === 0) {
  throw new Error('No hay filas válidas para exportar.');
}

return formatted;

