    url: 'https://api.openai.com/v1/chat/completions',
    headers: { 'Authorization': 'Bearer ' + $env.OPENAI_API_KEY },
    body: {
      model: 'gpt-4o',
      max_tokens: 4000,
      temperature: 0.5,
      response_format: { type: 'json_object' },
