    },
    json: true
  });
}

function wait(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

let lastError = null;
for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    const result = await callGPT.call(this);
    const content = result?.choices?.[0]?.message?.content;
    if (!content) throw new Error('Respuesta vacía de GPT-4o');
    JSON.parse(content.replace(/```json|```/g, '').trim());
    result._fileId = fileId;
    return { json: result };
  } catch (e) {
    lastError = e;
    if (attempt < MAX_RETRIES) await wait(RETRY_DELAY_MS * attempt);
